const cve = $input.first().json;
const cveid = cve.cve_id || cve.id || 'CVE-UNKNOWN';
const cvss = parseFloat(cve.cvss_score || cve.score || 0);
const description = cve.description || cve.summary || 'No description available';
const published = cve.published_date || cve.published || new Date().toISOString();
const affectedProducts = cve.affected_products || cve.products || [];
const activeExploit = cve.actively_exploited === true || cve.exploit_available === true;
const severity = cvss >= 9.0 ? 'CRITICAL' : cvss >= 7.0 ? 'HIGH' : cvss >= 4.0 ? 'MEDIUM' : 'LOW';
const emojiMap = { CRITICAL: '🚨', HIGH: '🔴', MEDIUM: '🟠', LOW: '🟡' };
return [{ json: { cveid, cvss, severity, description, published, affectedProducts, activeExploit, emoji: emojiMap[severity] || '🚨', humanTime: new Date(published).toUTCString() } }];

const analysisText = ($json.choices && $json.choices[0]) ? $json.choices[0].message.content : 'Analysis unavailable — check OpenAI API key';
const d = $('Build CVE Prompt').item.json.cve;
const exploitBadge = d.activeExploit ? '🚨 *ACTIVELY EXPLOITED*' : '';
const products = Array.isArray(d.affectedProducts) && d.affectedProducts.length > 0 ? d.affectedProducts.slice(0,3).join(', ') : 'See description';
return [{ json: {
  channel: $env.SLACK_CHANNEL_ID || 'general',
  text: d.emoji + ' CyberSentinel CVE Alert: ' + d.cveid + ' (CVSS ' + d.cvss + ')',
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: d.emoji + ' CVE Alert: ' + d.cveid } },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: '*CVSS Score:*\n' + d.cvss + ' (' + d.severity + ')' },
      { type: 'mrkdwn', text: '*Exploit Status:*\n' + (d.activeExploit ? '🚨 Actively Exploited' : '✅ No known exploit') },
      { type: 'mrkdwn', text: '*Affected Products:*\n' + products },
      { type: 'mrkdwn', text: '*Published:*\n' + d.humanTime }
    ]},
    { type: 'section', text: { type: 'mrkdwn', text: (exploitBadge ? exploitBadge + '\n' : '') + analysisText } },
    { type: 'divider' },
    { type: 'context', elements: [{ type: 'mrkdwn', text: 'Source: NVD/CISA  |  CyberSentinel AI Intelligence  |  ' + d.humanTime }] }
  ]
}}];
